mapper.select:
${pagingTop} SELECT a.book_idx, a.book_code, a.cate_id, a.book_name, a.author_name, a.book_pubname, a.isbn13, a.book_lend, a.lend_total, a.max_lend, a.book_reserve, a.com_code, TO_CHAR(a.book_pubdt, 'YYYY-MM-DD') AS book_pubdt, a.book_regdt, a.use_yn, a.type, a.format, a.book_image, a.parent_id, a.recommend_cnt, a.library_code, a.approved_yn, (SELECT z.cate_name FROM ELIB_CATEGORY z WHERE z.cate_id = a.cate_id) AS cate_name, CASE WHEN a.library_code = '9999999' THEN '통합' ELSE e.homepage_name END AS library_name, (SELECT z.cate_name FROM ELIB_CATEGORY z WHERE z.cate_id = a.parent_id) AS parent_name, d.book_info, (SELECT z.comp_name FROM ELIB_COMPANY z WHERE INSTR(z.com_code, a.com_code) > 0) AS comp_name, g.bestbook_idx, h.cat_bestbook_idx, a.device, CASE a.device WHEN '1' THEN 'PC' WHEN '2' THEN 'PC, 태블릿' WHEN '3' THEN 'PC, 태블릿, 스마트폰' END AS label FROM ELIB_BOOK a, ELIB_BOOKINFO d, CMS_HOMEPAGE e ,ELIB_BESTBOOK g ,ELIB_CATEGORY_BESTBOOK h WHERE a.use_yn != 'N' AND a.book_idx = d.book_idx AND a.library_code = SUBSTR(e.homepage_code(+), 1, 8) AND a.book_idx = g.book_idx (+) AND a.book_code = h.book_code (+)
AND a.type = #{type}
${pagingBottom}

${pagingTop} SELECT a.book_idx, a.book_code, a.cate_id, a.book_name, a.author_name, a.book_pubname, a.isbn13, a.book_lend, a.lend_total, a.max_lend, a.book_reserve, a.com_code, TO_CHAR(a.book_pubdt, 'YYYY-MM-DD') AS book_pubdt, TO_CHAR(a.add_date, 'YYYY-MM-DD') AS add_date, a.book_regdt, a.use_yn, a.type, a.format, a.book_image, a.parent_id, a.recommend_cnt, a.library_code, a.approved_yn, (SELECT z.cate_name FROM ELIB_CATEGORY z WHERE z.cate_id = a.cate_id) AS cate_name, CASE WHEN a.library_code = '9999999' THEN '통합' ELSE e.homepage_name END AS library_name, (SELECT z.cate_name FROM ELIB_CATEGORY z WHERE z.cate_id = a.parent_id) AS parent_name,
(SELECT z.comp_name FROM ELIB_COMPANY z WHERE INSTR(z.com_code, a.com_code) > 0) AS comp_name, g.bestbook_idx, h.cat_bestbook_idx, a.device, CASE a.device WHEN '1' THEN 'PC' WHEN '2' THEN 'PC, 태블릿' WHEN '3' THEN 'PC, 태블릿, 스마트폰' END AS label FROM ELIB_BOOK a, ELIB_BOOKINFO d, CMS_HOMEPAGE e ,ELIB_BESTBOOK g ,ELIB_CATEGORY_BESTBOOK h WHERE 1=1 AND a.book_idx = d.book_idx AND a.library_code = SUBSTR(e.homepage_code, 1, 8) AND a.book_idx = g.book_idx (+) AND a.book_code = h.book_code (+)
AND a.type = #{type}
AND g.bestbook_idx IS NULL
AND h.cat_bestbook_idx IS NULL
${pagingBottom}

SELECT
	COUNT(*) AS cnt
FROM
	ELIB_BOOK
WHERE
	book_code = #{book_code}
AND library_code = #{library_code}
AND com_code = #{com_code}

SELECT
	book_idx
FROM
	ELIB_BOOK
WHERE
	book_code = #{book_code}
AND	library_code = #{library_code}
AND com_code = #{com_code}

mapper.insert:
SELECT NVL(MAX(book_idx),0)+1 FROM ELIB_BOOK
INSERT INTO ELIB_BOOK ( book_idx, book_code, book_name, author_name, book_pubname, isbn13, format, book_image, parent_id, device, library_code, max_lend, use_yn, book_lend, book_reserve, com_code, book_pubdt, book_regdt, type, add_id, add_date, approved_yn, cate_id ) VALUES ( #{book_idx}, #{book_code}, #{book_name}, #{author_name}, #{book_pubname}, #{isbn13}, #{format}, #{book_image}, #{parent_id}, #{device}, #{library_code}, #{max_lend}, #{use_yn}, #{book_lend}, #{book_reserve}, #{com_code}, TO_DATE(#{book_pubdt}, 'YYYY-MM-DD'), SYSDATE, #{type}, #{add_id}, SYSDATE, #{approved_yn},
#{parent_id}
#{cate_id}
)

INSERT INTO ELIB_BOOKINFO (
	book_idx, book_code, book_info, author_info, book_table, add_id, add_date
) VALUES (
	#{book_idx}, #{book_code}, #{book_info}, #{author_info}, #{book_table}, #{add_id}, SYSDATE
)

mapper.update:
UPDATE ELIB_BOOK SET book_code = #{book_code}, book_name = #{book_name}, author_name = #{author_name}, book_pubname = #{book_pubname}, isbn13 = #{isbn13}, format = #{format}, book_image = #{book_image}, book_lend = #{book_lend}, book_reserve = #{book_reserve}, library_code = #{library_code}, com_code = #{com_code}, book_pubdt = TO_DATE(#{book_pubdt}, 'YYYY-MM-DD'), type = #{type}, use_yn = #{use_yn}, max_lend = #{max_lend}, parent_id = #{parent_id}, device = #{device}, mod_id = #{mod_id}, mod_date = SYSDATE,
cate_id = #{parent_id}
cate_id = #{cate_id}
WHERE book_idx = #{book_idx}

mapper.delete:
DELETE FROM ELIB_BOOK
WHERE book_idx = #{book_idx}
AND approved = 'N'

