	SELECT NVL(MAX(audio_idx),0)+1 FROM ELIB_AUDIOBOOK

INSERT INTO ELIB_AUDIOBOOK (
	audio_idx, book_idx, link_url, mobile_link_url, add_id, add_date, audio_no, audio_name
) values (
