INSERT INTO ELIB_RECOMMEND (
	recommend_idx, book_idx, regdt, member_id
) values (
	ELIB_RECOMMEND_SEQ.NEXTVAL, #{book_idx}, SYSDATE, #{member_id}
)

mapper.sql:
FROM ELIB_BOOK a,
CMS_HOMEPAGE e WHERE a.use_yn != 'N'
AND a.approved_yn = 'N'
AND a.approved_yn != 'N'
AND a.library_code = SUBSTR(e.homepage_code, 1, 8)
AND a.type = #{type}
AND a.author_name = #{author_name}
AND a.book_pubname = #{book_pubname}
AND TO_CHAR(a.book_pubdt, 'YYYY') = #{book_year}
AND a.device = #{device}
AND ( UPPER(REPLACE(a.book_name, ' ')) LIKE '%'||UPPER(REPLACE(#{search_text}, ' '))||'%' OR UPPER(REPLACE(a.author_name, ' ')) LIKE '%'||UPPER(REPLACE(#{search_text}, ' '))||'%' OR UPPER(REPLACE(a.book_pubname, ' ')) LIKE '%'||UPPER(REPLACE(#{search_text}, ' '))||'%'
)

