mapper.sql:
SELECT device, ( SELECT COUNT(*) FROM ELIB_BOOK z WHERE z.device = a.device and z.use_yn = 'Y'
and z.type = #{type}
and ( UPPER(REPLACE(z.book_name, ' ')) like '%'||UPPER(REPLACE(#{search_text}, ' '))||'%' or UPPER(REPLACE(z.author_name, ' ')) like '%'||UPPER(REPLACE(#{search_text}, ' '))||'%' or UPPER(REPLACE(z.book_pubname, ' ')) like '%'||UPPER(REPLACE(#{search_text}, ' '))||'%' )
AND z.approved_yn = #{approved_yn}
) AS cnt, CASE DEVICE WHEN '1' THEN 'PC' WHEN '2' THEN 'PC, 태블릿' WHEN '3' THEN 'PC, 태블릿, 스마트폰' END AS label FROM ELIB_BOOK a WHERE a.use_yn = 'Y'
AND a.approved_yn = 'N'
AND a.approved_yn != 'N'
and ( UPPER(REPLACE(book_name, ' ')) like '%'||UPPER(REPLACE(#{search_text}, ' '))||'%' or UPPER(REPLACE(author_name, ' ')) like '%'||UPPER(REPLACE(#{search_text}, ' '))||'%' or UPPER(REPLACE(book_pubname, ' ')) like '%'||UPPER(REPLACE(#{search_text}, ' '))||'%' )
GROUP BY device

